396→    public function saveMessages(Request $request): JsonResponse
397→    {
398→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
399→        if (!$this->inWhitelist($sfuserId)) {
400→            return $this->responseJsonFail('无权限');
401→        }
402→
403→        $roleId = $request->input('role_id');
404→        $sessionId = $request->input('session_id');
405→        $messages = $request->input('messages', []);
406→
407→        if (empty($messages)) {
408→            return $this->responseJsonFail('消息不能为空');
409→        }
410→
411→        // 无 session 则创建
412→        if (!$sessionId) {
413→            $firstUserMsg = collect($messages)->firstWhere('role', 'user');
414→            $title = mb_substr($firstUserMsg['content'] ?? '新会话', 0, 20);
415→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
416→                'sfuser_id' => $sfuserId,
417→                'role_id' => $roleId,
418→                'title' => $title,
419→                'created_at' => now(),
420→                'updated_at' => now(),
421→            ]);
422→        } else {
423→            // 校验会话归属
424→            $session = DB::table('daily_report_ai_sessions')
425→                ->where('id', $sessionId)
426→                ->where('sfuser_id', $sfuserId)
427→                ->whereNull('deleted_at')
428→                ->first();
429→            if (!$session) {
430→                return $this->responseJsonFail('会话不存在');
431→            }
432→            DB::table('daily_report_ai_sessions')
433→                ->where('id', $sessionId)
434→                ->update(['updated_at' => now()]);
435→        }
436→
437→        // 批量插入消息
438→        $rows = [];
439→        foreach ($messages as $msg) {
440→            $role = $msg['role'] ?? '';
441→            if (!in_array($role, ['user', 'assistant', 'context'])) {
442→                continue;
443→            }
444→            $rows[] = [
445→                'session_id' => $sessionId,
446→                'role' => $role,
447→                'content' => $msg['content'] ?? '',
448→                'created_at' => now(),
449→            ];
450→        }
451→        if (!empty($rows)) {
452→            DB::table('daily_report_ai_messages')->insert($rows);
453→        }
454→
455→        return $this->responseJsonSuccess(['session_id' => $sessionId]);
456→    }
