458→    public function extractSlots(Request $request): JsonResponse
459→    {
460→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
461→        if (!$this->inWhitelist($sfuserId)) {
462→            \Log::info('[lbl][0416-AI日报][AiSlots] 无权限', ['sfuser_id' => $sfuserId]);
463→            return $this->responseJsonFail('无权限');
464→        }
465→
466→        $message = $request->input('message');
467→        $conversationId = $request->input('conversation_id', '');
468→        $availableGroups = $request->input('available_groups', []);
469→        $availableMembers = $request->input('available_members', []);
470→        $previousContext = $request->input('previous_context');
471→        $hasExistingContext = $request->boolean('has_existing_context', false);
472→
473→        // 将可用分组和成员列表格式化为 prompt 中的列表
474→        $groupList = !empty($availableGroups)
475→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
476→            : '   - （无可用分组）';
477→        $memberList = !empty($availableMembers)
478→            ? implode('、', $availableMembers)
479→            : '（无可用成员列表）';
480→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
481→        $prevCtx = '无（首次查询）';
482→        if (!empty($previousContext)) {
483→            $prevMembers = implode('、', $previousContext['members'] ?? []);
484→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
485→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
486→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
487→        }
488→        $hasContextLabel = $hasExistingContext ? '是' : '否';
489→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
490→
491→        \Log::info('[lbl][0416-AI日报][AiSlots] request', [
492→            'sfuser_id' => $sfuserId,
493→            'message' => $message,
494→            'previous_context' => $previousContext,
495→            'available_groups' => $availableGroups,
496→            'member_count' => count($availableMembers),
497→        ]);
498→
499→        // 返回 message + ai_analysis_config，由 oa-core TransferRequestService 做 blocking AI 调用
500→        \Log::info('[lbl][0416-AI日报][AiSlots] response', [
501→            'sfuser_id' => $sfuserId,
502→            'message' => $message,
503→            'prompt_len' => mb_strlen($systemPrompt),
504→        ]);
505→        return $this->responseJsonSuccess([
506→            'message' => $message,
507→            'ai_analysis_config' => [
508→                'system_prompt' => $systemPrompt,
