1311→    public function getTokensByReportIds(array $reportIds): array
1312→    {
1313→        $tokens = [];
1314→        $emptyTokenIds = [];
1315→        foreach ($reportIds as $reportId) {
1316→            $tmp = redis()->get(DailyReport::REPORT_TOKEN_CACHE_PREFIX.$reportId);
1317→            if ($tmp) {
1318→                $tokens[] = $tmp;
1319→            } else {
1320→                $emptyTokenIds[] = $reportId;
1321→            }
1322→        }
1323→        if ($emptyTokenIds) {
1324→            $reports = DailyReport::whereIn('id', $emptyTokenIds)->select(['id', 'report_date', 'token'])->get()->toArray();
1325→            foreach ($reports as $report) {
1326→                $tokens[] = $report['token'];
1327→                $key = DailyReport::REPORT_TOKEN_CACHE_PREFIX.$report['id'];
1328→                if (redis()->exists($key)) {
1329→                    continue;
1330→                }
1331→                $ttl = strtotime("{$report['report_date']} +70 days") - time();
1332→                $ttl = $ttl > 0 ? $ttl : 70 * 3600 * 24;
1333→                redis()->set($key, $report['token']);
1334→                redis()->expire($key, $ttl);
1335→            }
1336→        }
1337→        return $tokens;
1338→    }
