```typescript
// Compute ISO week bounds for a given date
function getWeekBounds(date: string): { week_start: string; week_end: string }

// Compute week bounds for the "previous week" relative to today
function getLastWeekBounds(today: string): { week_start: string; week_end: string }

// Compute week bounds for the "current week"
function getCurrentWeekBounds(today: string): { week_start: string; week_end: string }

// Determine if today is Fri/Sat/Sun
function isTriggerDay(today: string): boolean

// Build the stats line from reports (total_chars, submit_days)
function computeSummaryStats(reports: DailyReportItem[]): { total_chars: number; submit_days: number }
